import java.io.*;
import java.util.*;

public class Main {
    private static final long MOD = 998244353L;
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            String S = br.readLine().trim();
            int n = S.length();
            long[] dp = new long[n + 1];
            dp[0] = 1; // empty prefix
            if (n >= 1) dp[1] = 1; // first character alone
            for (int i = 2; i <= n; i++) {
                long ways = dp[i - 1]; // take last character as a single block
                // block of length 2: "ab" or "ba"
                if (S.charAt(i - 2) != S.charAt(i - 1)) {
                    ways = (ways + dp[i - 2]) % MOD;
                }
                // block of length 3: "aba" or "bab"
                if (i >= 3) {
                    char c1 = S.charAt(i - 3);
                    char c2 = S.charAt(i - 2);
                    char c3 = S.charAt(i - 1);
                    if (c1 == c3 && c1 != c2) {
                        ways = (ways + dp[i - 3]) % MOD;
                    }
                }
                dp[i] = ways % MOD;
            }
            out.append(dp[n] % MOD).append('\n');
        }
        System.out.print(out.toString());
    }
}

